code.C:
#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long sum = 0;
        for (int i = 0; i < N; i++) {
            int a;
            scanf("%d", &a);
            sum += a;
        }
        printf("%.6f\n", (double)sum / N);
    }
    return 0;
}

