code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long sum = 0;
            for (int i = 0; i < N; i++) {
                int a = sc.nextInt();
                sum += a;
            }
            System.out.printf("%.6f\n", (double)sum / N);
        }
    }
}

